import React, { useState, useEffect } from 'react';
import { FormControl, InputLabel, Select, MenuItem, Chip, makeStyles } from '@material-ui/core';

const useStyles = makeStyles((theme) => ({
  formControl: {
    minWidth: 200,
    marginTop: theme.spacing(1),
  },
  chips: {
    display: 'flex',
    flexWrap: 'wrap',
  },
  chip: {
    margin: 2,
  },
}));

function CategorySelect({ selectedCategory, showExistingCategories, handleSelectChange, menuData, handleSubCategoryChange, selectedSubCategoryValues, existingCategories }) {
  const classes = useStyles();

  return (
    <FormControl className={classes.formControl}>
      <InputLabel id="category-label">Category</InputLabel>
      <Select
        labelId="category-label"
        id="category-select"
        value={selectedCategory}
        onChange={handleSelectChange}
        multiple
        renderValue={(selected) => (
          <div className={classes.chips}>
            {selected.map((value) => (
              <Chip key={value} label={value} className={classes.chip} />
            ))}
          </div>
        )}
      >
        {menuData.categories.map((category) => (
          <MenuItem key={category.mainMenu} value={category.mainMenu}>
            {category.mainMenu}
          </MenuItem>
        ))}
      </Select>
      <InputLabel id="subcategory-label">Subcategory</InputLabel>
      <Select
        labelId="subcategory-label"
        id="subcategory-select"
        value={selectedSubCategoryValues}
        onChange={handleSubCategoryChange}
        multiple
        renderValue={(selected) => (
          <div className={classes.chips}>
            {selected.map((value) => (
              <Chip key={value} label={value} className={classes.chip} />
            ))}
          </div>
        )}
      >
        {menuData.subCategories[selectedCategory]?.map((subCategory) => (
          <MenuItem key={subCategory} value={subCategory}>
            {subCategory}
          </MenuItem>
        ))}
      </Select>
    </FormControl>
  );
}

export default CategorySelect;
